from flask import Flask, send_from_directory, abort
import os

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/uploads/<path:filename>', methods=['GET'])
def serve_file(filename):
    if not allowed_file(filename):
        abort(404)
    
    # Legacy support: Check for older naming conventions
    legacy_filename = filename.replace('old_prefix_', 'new_prefix_')
    file_path = os.path.join(UPLOAD_FOLDER, legacy_filename)

    if os.path.isfile(file_path):
        return send_from_directory(UPLOAD_FOLDER, legacy_filename)

    # If legacy file not found, check for the current naming convention
    current_file_path = os.path.join(UPLOAD_FOLDER, filename)
    if os.path.isfile(current_file_path):
        return send_from_directory(UPLOAD_FOLDER, filename)

    abort(404)

if __name__ == '__main__':
    app.run(debug=True)